import os
import secrets
from flask import Flask, redirect, request, session, url_for, jsonify
import requests

app = Flask(__name__)
app.secret_key = os.environ.get('FLASK_SECRET_KEY', secrets.token_hex(32))

# OAuth 2.0 Configuration - Load from environment variables
OAUTH_CLIENT_ID = os.environ.get('OAUTH_CLIENT_ID')
OAUTH_CLIENT_SECRET = os.environ.get('OAUTH_CLIENT_SECRET')
OAUTH_AUTHORIZATION_URL = os.environ.get('OAUTH_AUTHORIZATION_URL')
OAUTH_TOKEN_URL = os.environ.get('OAUTH_TOKEN_URL')
OAUTH_REDIRECT_URI = os.environ.get('OAUTH_REDIRECT_URI')

@app.route('/')
def index():
    if 'access_token' in session:
        return jsonify({'message': 'Logged in', 'has_token': True})
    return jsonify({'message': 'Not logged in', 'has_token': False})

@app.route('/login')
def login():
    # Generate a cryptographically secure random state parameter
    state = secrets.token_urlsafe(32)
    
    # Store state in session for validation in callback
    session['oauth_state'] = state
    
    # Build authorization URL with state parameter
    auth_params = {
        'client_id': OAUTH_CLIENT_ID,
        'redirect_uri': OAUTH_REDIRECT_URI,
        'response_type': 'code',
        'state': state,
        'scope': 'openid profile email'
    }
    
    auth_url = f"{OAUTH_AUTHORIZATION_URL}?{'&'.join([f'{k}={v}' for k, v in auth_params.items()])}"
    
    return redirect(auth_url)

@app.route('/callback')
def callback():
    # Validate state parameter to prevent CSRF attacks
    received_state = request.args.get('state')
    stored_state = session.get('oauth_state')
    
    if not received_state or not stored_state or received_state != stored_state:
        session.pop('oauth_state', None)
        return jsonify({'error': 'Invalid state parameter'}), 400
    
    # Clear state from session after validation
    session.pop('oauth_state', None)
    
    # Get authorization code
    code = request.args.get('code')
    
    if not code:
        error = request.args.get('error', 'unknown_error')
        error_description = request.args.get('error_description', 'Authorization failed')
        return jsonify({'error': error, 'description': error_description}), 400
    
    # Exchange authorization code for access token
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OAUTH_REDIRECT_URI,
        'client_id': OAUTH_CLIENT_ID,
        'client_secret': OAUTH_CLIENT_SECRET
    }
    
    try:
        # Make POST request to token endpoint with timeout
        response = requests.post(
            OAUTH_TOKEN_URL,
            data=token_data,
            headers={'Accept': 'application/json'},
            timeout=10
        )
        
        # Check if request was successful
        if response.status_code != 200:
            return jsonify({'error': 'Token exchange failed', 'status': response.status_code}), 400
        
        token_response = response.json()
        
        # Validate token response
        access_token = token_response.get('access_token')
        if not access_token:
            return jsonify({'error': 'No access token in response'}), 400
        
        # Store access token securely in session (server-side)
        session['access_token'] = access_token
        
        # Optionally store refresh token if provided
        if 'refresh_token' in token_response:
            session['refresh_token'] = token_response['refresh_token']
        
        # Store token expiry if provided
        if 'expires_in' in token_response:
            session['token_expires_in'] = token_response['expires_in']
        
        return redirect(url_for('index'))
        
    except requests.exceptions.Timeout:
        return jsonify({'error': 'Token request timed out'}), 504
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Token request failed'}), 500
    except ValueError:
        return jsonify({'error': 'Invalid token response format'}), 500

@app.route('/logout')
def logout():
    # Clear session data
    session.pop('access_token', None)
    session.pop('refresh_token', None)
    session.pop('token_expires_in', None)
    return jsonify({'message': 'Logged out successfully'})

if __name__ == '__main__':
    # Ensure required environment variables are set
    required_vars = ['OAUTH_CLIENT_ID', 'OAUTH_CLIENT_SECRET', 'OAUTH_AUTHORIZATION_URL', 
                     'OAUTH_TOKEN_URL', 'OAUTH_REDIRECT_URI']
    
    missing_vars = [var for var in required_vars if not os.environ.get(var)]
    if missing_vars:
        print(f"Error: Missing required environment variables: {', '.join(missing_vars)}")
        exit(1)
    
    # Configure session security
    app.config.update(
        SESSION_COOKIE_SECURE=True,
        SESSION_COOKIE_HTTPONLY=True,
        SESSION_COOKIE_SAMESITE='Lax',
        PERMANENT_SESSION_LIFETIME=3600
    )
    
    app.run(ssl_context='adhoc')